github.bun_example:
import { integration } from '@velane/integrations'
const gh = integration('github')
const user = await gh.get('/user')
const issue = await gh.post('/repos/owner/repo/issues', { title: 'Bug', body: 'Details' })

gitlab.bun_example:
import { integration } from '@velane/integrations'
const gl = integration('gitlab')
const projects = await gl.get('/projects')

slack.bun_example:
import { integration } from '@velane/integrations'
const slack = integration('slack')
await slack.post('/chat.postMessage', { channel: '#general', text: 'Hello from Velane!' })

salesforce.bun_example:
import { integration } from '@velane/integrations'
const sf = integration('salesforce')
const c = await sf.post('/services/data/v60.0/sobjects/Case', { Subject: 'Login issue', Status: 'New' })
const found = await sf.get(`/services/data/v60.0/sobjects/Case/${c.id}`)

hubspot.bun_example:
import { integration } from '@velane/integrations'
const hs = integration('hubspot')
const contacts = await hs.get('/crm/v3/objects/contacts')
const deal = await hs.post('/crm/v3/objects/deals', { properties: { dealname: 'New Deal', amount: '5000' } })

notion.bun_example:
import { integration } from '@velane/integrations'
const notion = integration('notion')
const results = await notion.post('/search', { query: 'meeting notes' })

linear.bun_example:
import { integration } from '@velane/integrations'
const linear = integration('linear')
const data = await linear.post('/graphql', {
  query: `mutation { issueCreate(input: { title: "Bug", teamId: "TEAM_ID" }) { success issue { id title } } }`
})

jira.bun_example:
import { integration } from '@velane/integrations'
const jira = integration('jira')
const issue = await jira.post('/issue', { fields: { project: { key: 'PROJ' }, summary: 'Bug report', issuetype: { name: 'Bug' } } })

google-calendar.bun_example:
import { integration } from '@velane/integrations'
const cal = integration('google-calendar')
const event = await cal.post('/calendars/primary/events', {
  summary: 'Team sync',
  start: { dateTime: '2025-01-15T10:00:00Z' },
  end: { dateTime: '2025-01-15T11:00:00Z' }
})

google-sheets.bun_example:
import { integration } from '@velane/integrations'
const sheets = integration('google-sheets')
const data = await sheets.get('/spreadsheets/SHEET_ID/values/Sheet1!A1:D10')
await sheets.post('/spreadsheets/SHEET_ID/values/Sheet1!A:A:append?valueInputOption=USER_ENTERED', { values: [['new row']] })

